package org.example;

import io.appium.java_client.android.AndroidDriver;
import java.time.Duration;
import org.openqa.selenium.By;
import org.openqa.selenium.WebElement;
import org.openqa.selenium.support.ui.ExpectedConditions;
import org.openqa.selenium.support.ui.WebDriverWait;

public class BasePage {

    protected final AndroidDriver driver;
    protected final WebDriverWait wait;

    public BasePage(AndroidDriver driver) {
        this.driver = driver;
        this.wait = new WebDriverWait(driver, Duration.ofSeconds(10));
    }

    protected WebElement waitForVisible(By by) {
        return wait.until(ExpectedConditions.visibilityOfElementLocated(by));
    }

    protected void click(By by) {
        waitForVisible(by).click();
    }

    protected void sendKeys(By by, String text) {
        waitForVisible(by).sendKeys(text);
    }

    protected void clearAndSendKeys(By by, String text) {
        WebElement element = waitForVisible(by);
        element.clear();
        element.sendKeys(text);
    }

    protected String getText(By by) {
        return waitForVisible(by).getText();
    }
}

package pages;

import io.appium.java_client.android.AndroidDriver;
import org.openqa.selenium.By;

public class EditMatkulPage {

    AndroidDriver driver;

    By menuMatkul = By.id("menu_matkul");
    By btnEdit = By.id("btn_edit");
    By txtNamaMatkul = By.id("et_nama_matkul");
    By btnSimpan = By.id("btn_simpan");

    public EditMatkulPage(AndroidDriver driver){
        this.driver = driver;
    }

    public void bukaHalamanMatkul(){
        driver.findElement(menuMatkul).click();
    }

    public void klikEdit(){
        driver.findElement(btnEdit).click();
    }

    public void ubahNamaMatkul(String nama){
        driver.findElement(txtNamaMatkul).clear();
        driver.findElement(txtNamaMatkul).sendKeys(nama);
    }

    public void simpanPerubahan(){
        driver.findElement(btnSimpan).click();
    }
}

package pages;

import io.appium.java_client.android.AndroidDriver;
import org.example.BasePage;
import org.example.locators.MatkulLocators;

public class EditMatkulPage extends BasePage {

    public EditMatkulPage(AndroidDriver driver) {
        super(driver);
    }

    public void bukaHalamanMatkul() {
        click(MatkulLocators.MENU_MATKUL);
    }

    public void klikEdit() {
        click(MatkulLocators.BTN_EDIT);
    }

    public void ubahNamaMatkul(String nama) {
        clearAndSendKeys(MatkulLocators.INPUT_NAMA, nama);
    }

    public void simpanPerubahan() {
        click(MatkulLocators.BTN_SIMPAN);
    }
}

package pages;

import io.appium.java_client.android.AndroidDriver;
import org.example.BasePage;
import org.example.locators.MatkulLocators;

public class TambahMatkulPage extends BasePage {

    public TambahMatkulPage(AndroidDriver driver) {
        super(driver);
    }

    public void bukaHalamanDaftarMatkul() {
        click(MatkulLocators.MENU_MATKUL);
    }

    public void klikTambah() {
        click(MatkulLocators.BTN_TAMBAH);
    }

    public void isiNamaMatkul(String nama) {
        sendKeys(MatkulLocators.INPUT_NAMA, nama);
    }

    public void isiKodeMatkul(String kode) {
        sendKeys(MatkulLocators.INPUT_KODE, kode);
    }

    public void isiSks(String sks) {
        sendKeys(MatkulLocators.INPUT_SKS, sks);
    }

    public void klikSimpan() {
        click(MatkulLocators.BTN_SIMPAN);
    }

    public String ambilPesanAlert() {
        return getText(MatkulLocators.ALERT_MESSAGE);
    }

    public void tutupAlertSukses() {
        click(MatkulLocators.ALERT_OK);
    }
}

package runners;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
        features = "src/test/resources/add_matkul.feature",
        glue = {"stepDef"},
        plugin = {
                "pretty",
                "html:target/cucumber-report-add.html",
                "json:target/cucumber-add.json"
        },
        monochrome = true
)
public class TestRunnerAdd {
}

package stepDef;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.Then;
import io.cucumber.java.en.When;
import org.junit.Assert;
import pages.TambahMatkulPage;

public class AddMatkulSteps {

    TambahMatkulPage tambahMatkulPage;

    @Given("Admin sudah berada di halaman daftar mata kuliah")
    public void adminBeradaDiHalamanDaftarMatkul() {
        tambahMatkulPage.bukaHalamanDaftarMatkul();
    }

    @When("Admin mengeklik tombol tambah {string}")
    public void adminKlikTombolTambah(String tombolTambah) {
        tambahMatkulPage.klikTambah();
    }

    @When("Admin memasukkan nama mata kuliah {string}")
    public void adminMasukkanNamaMatkul(String nama) {
        tambahMatkulPage.isiNamaMatkul(nama);
    }

    @When("Admin memasukkan kode mata kuliah {string}")
    public void adminMasukkanKodeMatkul(String kode) {
        tambahMatkulPage.isiKodeMatkul(kode);
    }

    @When("Admin memasukkan jumlah SKS {string}")
    public void adminMasukkanSks(String sks) {
        tambahMatkulPage.isiSks(sks);
    }

    @When("Admin mengeklik tombol {string}")
    public void adminKlikTombolSimpan(String tombolSimpan) {
        tambahMatkulPage.klikSimpan();
    }

    @Then("Sistem harus menampilkan alert sukses dengan pesan {string}")
    public void sistemTampilkanAlertSukses(String pesan) {
        Assert.assertEquals(pesan, tambahMatkulPage.ambilPesanAlert());
    }

    @Then("Admin mengeklik OK untuk menutup alert sukses")
    public void adminTutupAlertSukses() {
        tambahMatkulPage.tutupAlertSukses();
    }
}
